import logo from './logo.svg';

import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';

import NavigationBar from './NavigationBar';
import SimpleCarousel from './SimpleCarousel';
import ScrollProgressBar from './ScrollProgressBar';
import CollapsedText from './CollapsedText';
import { Parallax, ParallaxLayer } from '@react-spring/parallax';
import { useRef } from 'react';

import moon from './pics/moon.png';
import land from './pics/land.png';
import cat from './pics/cat.gif';

function App() {

  const ref = useRef();

  return (
    <div className="App">
      <header>
        <NavigationBar refProp={ref} />
      </header>

      <body>

        <Parallax pages={4} ref={ref}>

          <ParallaxLayer
            offset={0}
            speed={1}
            factor={2}
          >
            <SimpleCarousel />
            <CollapsedText />
          </ParallaxLayer>
          <ParallaxLayer
            offset={2}
            speed={1}
            factor={4}
          >
            <SimpleCarousel />
            <CollapsedText />
          </ParallaxLayer>

          <ParallaxLayer
            sticky={{ start: 0.9, end: 2.5 }}
            style={{ textAlign: 'center' }}
          >
          </ParallaxLayer>

          <ParallaxLayer
            offset={0.2}
            speed={0.05}
          >
            <h2>Welcome to my website</h2>
          </ParallaxLayer>

          <ParallaxLayer
            offset={3}
            speed={2}
          >
            <h2>Hi Mom!</h2>
          </ParallaxLayer>
        </Parallax>

        {/*
        <section id="section-0">
          
        </section>
        <section id="section-1">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-2">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-3">
          <SimpleCarousel />
          <CollapsedText />
        </section>
        <section id="section-4">
          <SimpleCarousel />
          <CollapsedText />
        </section>
          */}
      </body>

      <footer>
        <ScrollProgressBar />
      </footer>
    </div>
  );
}


export default App;
